{"content": "     1|// Product CRUD API — reads/writes products from content/es.json
     2|import { NextRequest, NextResponse } from "next/server"
     3|import { readFile, writeFile } from "fs/promises"
     4|import { join } from "path"
     5|
     6|const CONTENT_FILE = join(process.cwd(), "content", "es.json")
     7|
     8|export async function GET() {
     9|  try {
    10|    const data = JSON.parse(await readFile(CONTENT_FILE, "utf-8"))
    11|    return NextResponse.json(data.home?.productCatalog?.products || [])
    12|  } catch {
    13|    return NextResponse.json({ error: "Error reading products" }, { status: 500 })
    14|  }
    15|}
    16|
    17|export async function PATCH(request: NextRequest) {
    18|  try {
    19|    const { name, updates } = await request.json()
    20|    const data = JSON.parse(await readFile(CONTENT_FILE, "utf-8"))
    21|    const products = data.home?.productCatalog?.products || []
    22|    const idx = products.findIndex((p: any) => p.name === name)
    23|    if (idx === -1) return NextResponse.json({ error: "Product not found" }, { status: 404})
    24|    products[idx] = { ...products[idx], ...updates }
    25|    data.home.productCatalog.products = products
    26|    // Sync to productos page
    27|    data.productos.productCatalog.products = products
    28|    await writeFile(CONTENT_FILE, JSON.stringify(data, null, 2))
    29|    return NextResponse.json({ success: true, product: products[idx] })
    30|  } catch {
    31|    return NextResponse.json({ error: "Error updating product" }, { status: 500 })
    32|  }
    33|}
