     2|import { NextRequest, NextResponse } from "next/server"
     3|import { readFile, writeFile, mkdir } from "fs/promises"
     4|import { join } from "path"
     5|
     6|const DATA_DIR = join(process.cwd(), "data")
     7|const CART_FILE = join(DATA_DIR, "abandoned-carts.json")
     8|
     9|async function getCarts(): Promise<any[]> {
    10|  try {
    11|    const data = await readFile(CART_FILE, "utf-8")
    12|    return JSON.parse(data)
    13|  } catch { return [] }
    14|}
    15|
    16|async function saveCarts(carts: any[]) {
    17|  await mkdir(DATA_DIR, { recursive: true })
    18|  await writeFile(CART_FILE, JSON.stringify(carts, null, 2))
    19|}
    20|
    21|export async function POST(request: NextRequest) {
    22|  try {
    23|    const { phone, items, total } = await request.json()
    24|    if (!phone) return NextResponse.json({ error: "Phone required" }, { status: 400 })
    25|    const carts = await getCarts()
    26|    carts.push({
    27|      id: `CART-${Date.now()}`,
    28|      phone, items, total,
    29|      createdAt: new Date().toISOString(),
    30|      remindersSent: 0,
    31|      recovered: false
