  status TEXT NOT NULL DEFAULT 'pendiente',
  address_id TEXT DEFAULT '',
  payment_method TEXT DEFAULT '',
  note TEXT DEFAULT '',
  created_at TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE public.ej_orders ENABLE ROW LEVEL SECURITY;

