  created_at TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE public.ej_reviews ENABLE ROW LEVEL SECURITY;

-- RLS policies
CREATE POLICY "ej_products_read_public" ON public.ej_products FOR SELECT USING (true);
CREATE POLICY "ej_products_write_admin" ON public.ej_products FOR ALL USING (auth.jwt() ->> 'role' = 'service_role');
