CREATE POLICY "ej_reviews_read_public" ON public.ej_reviews FOR SELECT USING (true);
CREATE POLICY "ej_reviews_insert_auth" ON public.ej_reviews FOR INSERT WITH CHECK (auth.role() = 'authenticated');
CREATE POLICY "ej_reviews_delete_admin" ON public.ej_reviews FOR DELETE USING (auth.jwt() ->> 'role' = 'service_role');

-- Seed elviajero products
SQLEOF
