import { AdminShell, useAdminAuth } from "@/components/admin/admin-layout"
import { useState, useEffect } from "react"
import { createClient } from "@/lib/supabase/client"

function DashboardContent() {
  const { authed } = useAdminAuth()
  const supabase = createClient()
  const [stats, setStats] = useState({ users: 0, orders: 0, revenue: 0, products: 0, monthOrders: 0, monthRevenue: 0 })
  const [recentOrders, setRecentOrders] = useState<any[]>([])

  useEffect(() => {
    if (!authed) return
    async function load() {
      const { count: userCount } = await supabase.from('profiles').select('*', { count: 'exact', head: true })
      const { count: prodCount } = await supabase.from('ej_products').select('*', { count: 'exact', head: true })
      const { data: ords } = await supabase.from('ej_orders').select('total, status, created_at').order('created_at', { ascending: false })
      const parse = (s: string) => parseInt(s.replace(/[^0-9]/g, ''), 10) || 0
      const totalRevenue = (ords || []).reduce((s, o) => s + parse(o.total), 0)
      const monthAgo = new Date(Date.now() - 30 * 86400000).toISOString()
      const monthOrds = (ords || []).filter(o => o.created_at >= monthAgo)
      const monthRevenue = monthOrds.reduce((s, o) => s + parse(o.total), 0)
      setStats({ users: userCount || 0, orders: ords?.length || 0, revenue: totalRevenue, products: prodCount || 0, monthOrders: monthOrds.length, monthRevenue })
      setRecentOrders((ords || []).slice(0, 5))
    }
    load()
  }, [authed, supabase])

  const format = (n: number) => 'Gs. ' + n.toLocaleString('es-PY')

  if (!authed) return null

  return (
    <>
      <h1 className="mb-6 text-xl font-bold text-white">Dashboard</h1>
      <div className="grid grid-cols-2 gap-4 mb-8 lg:grid-cols-5">
        {[
          { label: 'Usuarios', value: stats.users.toString(), color: 'text-blue-400' },
          { label: 'Productos', value: stats.products.toString(), color: 'text-purple-400' },
          { label: 'Pedidos totales', value: stats.orders.toString(), color: 'text-green-400' },
          { label: 'Pedidos del mes', value: stats.monthOrders.toString(), color: 'text-amber-400' },
          { label: 'Ingresos del mes', value: format(stats.monthRevenue), color: 'text-emerald-400' },
        ].map((s) => (
          <div key={s.label} className="rounded-xl border border-gray-800 bg-gray-900 p-4">
            <p className="text-xs text-gray-500">{s.label}</p>
            <p className={'text-2xl font-bold mt-1 ' + s.color}>{s.value}</p>
          </div>
        ))}
      </div>
      {recentOrders.length > 0 && (
        <>
          <h2 className="mb-3 text-lg font-bold text-white">Pedidos recientes</h2>
          <div className="space-y-2">
            {recentOrders.map((o) => (
              <div key={o.id} className="flex items-center justify-between rounded-xl border border-gray-800 bg-gray-900 p-3">
                <div>
                  <p className="text-sm font-medium text-white">#{o.id?.slice(0, 8)}</p>
                  <p className="text-xs text-gray-500">{o.created_at ? new Date(o.created_at).toLocaleDateString('es') : ''}</p>
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-white">{o.total}</p>
                  <span className={'rounded-full px-2 py-0.5 text-xs font-semibold ' + (
                    o.status === 'pendiente' ? 'bg-yellow-900/30 text-yellow-400' :
                    o.status === 'confirmado' ? 'bg-green-900/30 text-green-400' :
                    o.status === 'cancelado' ? 'bg-red-900/30 text-red-400' :
                    'bg-blue-900/30 text-blue-400'
                  )}>{o.status}</span>
                </div>
              </div>
            ))}
          </div>
        </>
      )}
    </>
  )
}

export default function AdminPage() { return <AdminShell><DashboardContent /></AdminShell> }"""

