  if (!authed) return null

  return (
    <>
      <div className="mb-6 flex items-center justify-between">
        <h1 className="text-xl font-bold text-white">Pedidos ({orders.length})</h1>
      </div>
      <div className="mb-4 flex flex-wrap gap-2">
        {["todos", ...statuses].map(s => (
          <button key={s} onClick={() => setFilter(s)}
            className={'rounded-full px-3 py-1 text-xs font-medium ' + (filter === s ? 'bg-green-600 text-white' : 'bg-gray-800 text-gray-400 hover:text-white')}>
            {s === "todos" ? "Todos" : s}{s !== "todos" ? ' (' + (counts[s] || 0) + ')' : ''}
          </button>
        ))}
      </div>
      {loading ? (
        <div className="text-center py-12 text-gray-500 text-sm">Cargando...</div>
      ) : (
        <div className="space-y-3">
          {filtered.map(o => (
            <div key={o.id} className="rounded-xl border border-gray-800 bg-gray-900 p-4">
              <div className="flex items-center justify-between mb-2">
                <span className="font-bold text-white">#{o.id?.slice(0, 8)}</span>
                <span className="text-xs text-gray-500">{o.created_at ? new Date(o.created_at).toLocaleDateString("es", { dateStyle: "long" }) : ""}</span>
              </div>
              <div className="flex items-center justify-between">
                <div className="text-sm">
                  <p className="text-gray-400">{o.user_id?.slice(0, 8) || "Invitado"} · {o.items?.length || 0} artículos</p>
                  <p className="text-white font-bold mt-1">{o.total}</p>
                  {o.payment_method && <p className="text-xs text-gray-500 mt-0.5">Pago: {o.payment_method}</p>}
                </div>
                <select value={o.status} onChange={e => update(o.id, e.target.value)}
