{"content": "const EVOLUTION_API_BASE = process.env.EVOLUTION_API_BASE || 'http://evolution_evolution_api:8080'
const EVOLUTION_API_KEY = process.env.EVOLUTION_API_KEY || ''
const INSTANCE_NAME = process.env.WHATSAPP_INSTANCE || 'elviajero'

export async function sendWhatsApp(to: string, message: string): Promise<boolean> {
  if (!EVOLUTION_API_KEY) {
    console.log('[WhatsApp] No API key configured. Would send:', message.substring(0, 100))
    return false
  }

  try {
    const res = await fetch(`${EVOLUTION_API_BASE}/message/sendText/${INSTANCE_NAME}`, {
      method: 'POST',
      headers: { 'apikey': EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify({ number: to, text: message, delay: 1200 }),
    })
    if (!res.ok) {
      const text = await res.text()
      console.error('[WhatsApp] Send failed:', text.substring(0, 200))
      return false
    }
    return true
  } catch (err) {
    console.error('[WhatsApp] Error:', err)
    return false
  }
}

export async function notifyNewOrder(order: any) {
  const ADMIN_NUMBER = process.env.ADMIN_WHATSAPP || '[REDACTED_PHONE]'
  const msg = `🆕 Nuevo pedido #${order.id?.slice(0, 8)}\nTotal: ${order.total}\nPago: ${order.payment_method || 'whatsapp'}\nEnvío: ${order.note || '—'}\n\nMirá el panel: https://el-viajero.paragu-ai.com/admin/pedidos`

  await sendWhatsApp(ADMIN_NUMBER, msg)
}

export async function notifyStatusChange(orderId: string, customerPhone: string, newStatus: string) {
  const statusLabels: Record<string, string> = {
    confirmado: '✅ Tu pedido fue confirmado',
    enviado: '🚚 Tu pedido fue enviado',
    entregado: '📦 Tu pedido fue entregado',
    cancelado: '❌ Tu pedido fue cancelado',
  }

  const msg = `👋 Hola! Soy El Viajero.\n\n${statusLabels[newStatus] || '📋 Estado actualizado: ' + newStatus}\nPedido: #${orderId?.slice(0, 8)}\n\nAnte cualquier duda, respondé este mensaje.`

  await sendWhatsApp(customerPhone, msg)
}
