          )}
          <button onClick={onCartClick} className="relative flex h-9 w-9 items-center justify-center rounded-md">
            {itemCount > 0 && <span className="absolute -right-0.5 -top-0.5 flex h-4 items-center justify-center rounded-full bg-accent px-1 text-[10px] font-bold">{itemCount}</span>}
          </button>
          <button onClick={() => setMobileOpen(!mobileOpen)} className="md:hidden px-2 py-2">☰</button>
        </div>
      </div>

      {mobileOpen && (
        <div className="border-t px-4 py-2 md:hidden">
          {user ? (
            <div className="mb-3 rounded-xl border bg-surface p-3">
              <p className="text-sm font-medium">{user.name}</p>
              <div className="flex gap-2 mt-2">
                <Link href="/mi-cuenta" onClick={() => setMobileOpen(false)} className="rounded-md bg-primary/10 px-3 py-1.5 text-xs text-primary">Mi Cuenta</Link>
                {user.role === "admin" && <Link href="/admin" onClick={() => setMobileOpen(false)} className="rounded-md bg-green-600/10 px-3 py-1.5 text-xs text-green-600">Admin</Link>}
                <button onClick={() => { supabase.auth.signOut(); setUser(null); setMobileOpen(false) }} className="rounded-md bg-red-500/10 px-3 py-1.5 text-xs text-red-500">Salir</button>
              </div>
            </div>
          ) : (
            <Link href="/login" onClick={() => setMobileOpen(false)} className="mb-3 flex items-center justify-center gap-2 rounded-xl bg-primary p-3 text-sm font-semibold text-primary-foreground">
              Iniciar Sesión / Registrarse
            </Link>
          )}
        </div>
      )}
    </header>
  )
}
"}
